-- whitelist
local Players = game:GetService("Players")
local Player = Players.LocalPlayer

local WHITELIST = {
	"alt_simontoys",
	"ziranji1",
	"madalinboss659",
	"Nayf890077",
	"koala102365",
	"carburatoru4",
	"AnthonyEnte17",
	"SiMpLE_77173",
	"kosovaboyy1",
	"Gerry_rp2",
	"xZryeennn",
	"Etmalkingi",
	"Cript1305",
	"justsigma2crazy",
	"silverminite01",
    "Kqlayr"
}

local function isWhitelisted(name)
	for _,v in ipairs(WHITELIST) do
		if v:lower() == name:lower() then
			return true
		end
	end
	return false
end

if not isWhitelisted(Player.Name) then
	Player:Kick("Not Whitelisted")
	return
end


